#include <stdio.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int prev, cur;
        int blocks = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &cur);
            if (i == 0 || cur != prev) ++blocks;
            prev = cur;
        }
        printf("%d\n", blocks);
    }
    return 0;
}

