const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  let blocks = 0;
  let prev = null;
  for (let i = 0; i < N; ++i) {
    const cur = Number(input[idx++]);
    if (i === 0 || cur !== prev) blocks++;
    prev = cur;
  }
  outputs.push(String(blocks));
}
